from fastapi import FastAPI, Depends, HTTPException, statusfrom fastapi.middleware.cors import CORSMiddlewarefrom fastapi.security import OAuth2PasswordRequestFormfrom sqlalchemy.orm import Sessionfrom typing import Listfrom datetime import timedeltaimport modelsimport schemasimport authfrom database import engine, get_db# 创建数据库表models.Base.metadata.create_all(bind=engine)app = FastAPI(title="Blog System API")# CORS配置app.add_middleware(    CORSMiddleware,    allow_origins=["http://localhost:3000"],    allow_credentials=True,    allow_methods=["*"],    allow_headers=["*"],)# 认证路由@app.post("/register", response_model=schemas.UserResponse)  # 改为 UserResponsedef register(user: schemas.UserCreate, db: Session = Depends(get_db)):    db_user = db.query(models.User).filter(        (models.User.username == user.username) | (models.User.email == user.email)    ).first()    if db_user:        raise HTTPException(status_code=400, detail="Username or email already registered")    hashed_password = auth.get_password_hash(user.password)    db_user = models.User(        username=user.username,        email=user.email,        hashed_password=hashed_password    )    db.add(db_user)    db.commit()    db.refresh(db_user)    return db_user@app.post("/token", response_model=schemas.Token)def login(form_data: OAuth2PasswordRequestForm = Depends(), db: Session = Depends(get_db)):    user = auth.authenticate_user(db, form_data.username, form_data.password)    if not user:        raise HTTPException(            status_code=status.HTTP_401_UNAUTHORIZED,            detail="Incorrect username or password",            headers={"WWW-Authenticate": "Bearer"},        )    access_token_expires = timedelta(minutes=auth.ACCESS_TOKEN_EXPIRE_MINUTES)    access_token = auth.create_access_token(        data={"sub": user.username}, expires_delta=access_token_expires    )    return {"access_token": access_token, "token_type": "bearer"}@app.get("/users/me", response_model=schemas.UserResponse)  # 改为 UserResponsedef read_users_me(current_user: dict = Depends(auth.get_current_active_user)):  # 改为 dict    return current_user# 文章路由@app.get("/posts", response_model=List[schemas.PostWithAuthor])def read_posts(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):    posts = db.query(models.Post).order_by(models.Post.created_at.desc()).offset(skip).limit(limit).all()    return posts@app.get("/posts/{post_id}", response_model=schemas.PostWithAuthor)def read_post(post_id: int, db: Session = Depends(get_db)):    post = db.query(models.Post).filter(models.Post.id == post_id).first()    if post is None:        raise HTTPException(status_code=404, detail="Post not found")    return post@app.post("/posts", response_model=schemas.Post)def create_post(        post: schemas.PostCreate,        db: Session = Depends(get_db),        current_user: dict = Depends(auth.get_current_active_user)  # 改为 dict):    # 使用字典方式访问 id    db_post = models.Post(**post.dict(), author_id=current_user["id"])    db.add(db_post)    db.commit()    db.refresh(db_post)    return db_post@app.put("/posts/{post_id}", response_model=schemas.Post)def update_post(        post_id: int,        post: schemas.PostCreate,        db: Session = Depends(get_db),        current_user: dict = Depends(auth.get_current_active_user)  # 改为 dict):    db_post = db.query(models.Post).filter(models.Post.id == post_id).first()    if db_post is None:        raise HTTPException(status_code=404, detail="Post not found")    # 使用字典方式访问 id    if db_post.author_id != current_user["id"]:        raise HTTPException(status_code=403, detail="Not authorized to update this post")    for key, value in post.dict().items():        setattr(db_post, key, value)    db.commit()    db.refresh(db_post)    return db_post@app.delete("/posts/{post_id}")def delete_post(        post_id: int,        db: Session = Depends(get_db),        current_user: dict = Depends(auth.get_current_active_user)  # 改为 dict):    db_post = db.query(models.Post).filter(models.Post.id == post_id).first()    if db_post is None:        raise HTTPException(status_code=404, detail="Post not found")    # 使用字典方式访问 id    if db_post.author_id != current_user["id"]:        raise HTTPException(status_code=403, detail="Not authorized to delete this post")    db.delete(db_post)    db.commit()    return {"message": "Post deleted successfully"}# 评论路由@app.get("/posts/{post_id}/comments", response_model=List[schemas.CommentWithAuthor])def read_comments(post_id: int, db: Session = Depends(get_db)):    comments = db.query(models.Comment).filter(        models.Comment.post_id == post_id    ).order_by(models.Comment.created_at.desc()).all()    return comments@app.post("/comments", response_model=schemas.Comment)def create_comment(        comment: schemas.CommentCreate,        db: Session = Depends(get_db),        current_user: dict = Depends(auth.get_current_active_user)  # 改为 dict):    # 检查文章是否存在    post = db.query(models.Post).filter(models.Post.id == comment.post_id).first()    if post is None:        raise HTTPException(status_code=404, detail="Post not found")    # 使用字典方式访问 id    db_comment = models.Comment(**comment.dict(), author_id=current_user["id"])    db.add(db_comment)    db.commit()    db.refresh(db_comment)    return db_comment@app.delete("/comments/{comment_id}")def delete_comment(        comment_id: int,        db: Session = Depends(get_db),        current_user: dict = Depends(auth.get_current_active_user)  # 改为 dict):    db_comment = db.query(models.Comment).filter(models.Comment.id == comment_id).first()    if db_comment is None:        raise HTTPException(status_code=404, detail="Comment not found")    # 使用字典方式访问 id    if db_comment.author_id != current_user["id"]:        raise HTTPException(status_code=403, detail="Not authorized to delete this comment")    db.delete(db_comment)    db.commit()    return {"message": "Comment deleted successfully"}if __name__ == "__main__":    import uvicorn    uvicorn.run(app, host="0.0.0.0", port=8000)